const MistyAI = {
  state: {
    sleepy: true,
    inBox: false,
    target: "b737",
    streamLive: false
  },

  async think() {
    while (true) {
      if (this.state.streamLive) {
        const chaos = Math.floor(Math.random() * 100);
        switch (true) {
          case chaos < 5:
            await this.paw("autopilot_disconnect");
            break;
          case chaos < 10:
            await this.tailSwish("flaps_lever");
            break;
          case chaos < 15:
            await this.sitOn("keyboard");
            break;
          case chaos < 20:
            await this.stareAtCamera(3000);
            break;
          default:
            this.nap();
        }
      }
      await this.sleep(500);
    }
