const mistyAdvanced = {
  boxCollection: [],
  autopilotDisengaged: 0,
  flapsExtended: false,

  boxEnterSequence: function(box) {
    if (box.isCardboard && box.isEmpty) {
      this.boxCollection.push(box);
      return "*squeezes in* :box:";
    } else if (box.containsHuman) {
      return "*stares judgmentally* :MistyStare:";
    }
  },

  flightSimulation: function(aircraft) {
    if (aircraft === "Boeing737") {
      this.stepOnHardware("autopilot_button");
      this.stepOnHardware("flaps_lever");
      this.autopilotDisengaged++;
      this.flapsExtended = true;
      return `*CRUISE ALTITUDE DESTABILIZED* :incident:`;
    }
  },

  meowAttempt: function() {
    const attempts = ["*opens mouth*", "*silent scream*", "*breath noise*"];
    return attempts[Math.floor(Math.random() * 3)];
  },

  sleepMode: function() {
    return "*powers down on keyboard* :emoji_130:";
  }
};

// Runtime loop
while (true) {
  if (mistyAdvanced.detectBox()) {
    mistyAdvanced.boxEnterSequence(box);
  } else if (mistyAdvanced.detect737()) {
    mistyAdvanced.flightSimulation("Boeing737");
  } else {
    mistyAdvanced.sleepMode();
  }
}
